// Daily Briefing formatieren
const tasks = $('Get Tasks').all();
const events = $('Get Calendar Events').all();
const today = new Date().toISOString().split('T')[0];

// Tasks filtern: heute faellig oder ueberfaellig
const todayTasks = [];
const overdueTasks = [];
const upcomingTasks = [];

for (const t of tasks) {
  const task = t.json;
  const title = task.title || 'Ohne Titel';
  const due = task.due ? task.due.split('T')[0] : null;
  const notes = task.notes || '';

  // Prio aus Notes extrahieren
  const prioMatch = notes.match(/Prio:\s*(\w+)/);
  const prio = prioMatch ? prioMatch[1] : '-';

  if (due === today) {
    todayTasks.push(`• ${title} [${prio}]`);
  } else if (due && due < today) {
    overdueTasks.push(`• ${title} (faellig: ${due}) [${prio}]`);
  } else {
    upcomingTasks.push({ title, due, prio });
  }
}

// Events formatieren
const eventLines = events.map(e => {
  const ev = e.json;
  const start = ev.start?.dateTime ? new Date(ev.start.dateTime).toLocaleTimeString('de-DE', {hour:'2-digit', minute:'2-digit'}) : 'ganztaegig';
  const end = ev.end?.dateTime ? new Date(ev.end.dateTime).toLocaleTimeString('de-DE', {hour:'2-digit', minute:'2-digit'}) : '';
  return `• ${start}${end ? '-'+end : ''} ${ev.summary || 'Termin'}`;
});

// Briefing zusammenbauen
let msg = `Guten Morgen! Dein Tag (${today}):\n\n`;

if (todayTasks.length > 0) {
  msg += `📋 Tasks heute (${todayTasks.length}):\n${todayTasks.join('\n')}\n\n`;
} else {
  msg += `📋 Keine Tasks heute faellig.\n\n`;
}

if (overdueTasks.length > 0) {
  msg += `⚠️ Ueberfaellig (${overdueTasks.length}):\n${overdueTasks.join('\n')}\n\n`;
}

if (eventLines.length > 0) {
  msg += `📅 Termine:\n${eventLines.join('\n')}\n\n`;
} else {
  msg += `📅 Keine Termine heute.\n\n`;
}

// Naechste 3 Tasks
const next3 = upcomingTasks.slice(0, 3);
if (next3.length > 0) {
  msg += `🔜 Naechste Tasks:\n${next3.map(t => `• ${t.title} (${t.due || 'kein Datum'}) [${t.prio}]`).join('\n')}\n`;
}

msg += `\n---\nTotal offene Tasks: ${tasks.length}`;

return [{ json: { briefing: msg } }];

// E-Mail Metadaten extrahieren
const email = items[0].json;

function generateULID() {
  const ENCODING = '0123456789ABCDEFGHJKMNPQRSTVWXYZ';
  let now = Date.now();
  let timeStr = '';
  for (let i = 9; i >= 0; i--) {
    timeStr = ENCODING[now % 32] + timeStr;
    now = Math.floor(now / 32);
  }
  let randomStr = '';
  for (let i = 0; i < 16; i++) {
    randomStr += ENCODING[Math.floor(Math.random() * 32)];
  }
  return timeStr + randomStr;
}

const subject = email.subject || email.headers?.subject || 'Kein Betreff';
const from = email.from || email.headers?.from || 'unbekannt';
const threadId = email.threadId || email.id || '';
const messageId = email.id || email.messageId || '';

return [{
  json: {
    subject,
    from,
    threadId,
    messageId,
    event_id: generateULID(),
    taskTitle: `[Email] ${subject}`,
    taskNotes: `Von: ${from}\nThread: ${threadId}\nMessage: ${messageId}\nEvent: ${generateULID()}`
  }
}];

function generateULID() {
  const E = '0123456789ABCDEFGHJKMNPQRSTVWXYZ';
  let now = Date.now(), t = '';
  for (let i = 9; i >= 0; i--) { t = E[now % 32] + t; now = Math.floor(now / 32); }
  let r = '';
  for (let i = 0; i < 16; i++) r += E[Math.floor(Math.random() * 32)];
  return t + r;
}

function parseCommand(text) {
  if (!text) return { command: 'unknown', title: '', params: {}, raw: '' };
  text = text.trim();
  const m = text.match(/^([tfkqwmh]):\s*(.*)/is);
  if (!m) return { command: 'unknown', title: text, params: {}, raw: text };
  const command = m[1].toLowerCase();
  let rest = m[2];
  const params = {};
  const re = /\/(\w+)=([^\s\/]+)/g;
  let match;
  while ((match = re.exec(rest)) !== null) params[match[1]] = match[2];
  const title = rest.replace(/\/\w+=[^\s\/]+/g, '').trim();
  return { command, title, params, raw: text };
}

const msg = items[0].json.message || items[0].json;
const text = msg.text || '';
const msgId = msg.message_id || '';
const chatId = msg.chat?.id || '';

if (chatId.toString() !== '6526468834') { return []; }

const parsed = parseCommand(text);

const routeMap = { t:'google_tasks_next', f:'google_tasks_waiting', k:'obsidian_inbox', q:'google_calendar_freebusy', w:'notion_health', m:'obsidian_inbox', h:'notion_health' };
const typeMap = { t:'task.create', f:'followup.create', k:'knowledge.draft', q:'calendar.query', w:'workout.log', m:'meeting.create', h:'health.log' };

return [{
  json: {
    command: parsed.command,
    title: parsed.title,
    params: parsed.params,
    chat_id: chatId,
    message_id: msgId,
    event_id: generateULID(),
    event_type: typeMap[parsed.command] || 'unknown',
    routing: routeMap[parsed.command] || 'unknown',
    timestamp: new Date().toISOString()
  }
}];

const item = items[0].json;
const date = new Date().toISOString().split('T')[0];
const title = item.title || 'Unbenannt';
const filename = date + ' - ' + title + '.md';

const frontmatter = [
  '---',
  'id: ' + item.event_id,
  'date: ' + date,
  'source: telegram',
  'source_id: msg_' + item.message_id,
  'topic: ' + (item.params.topic || ''),
  'project_id: ' + (item.params.project || item.params.p || ''),
  'status: draft',
  'review_state: pending',
  'tags:',
  '  - knowledge',
  '  - inbox',
  '---',
].join('\n');

const content = frontmatter + '\n\n# ' + title + '\n\n> [!info] Quelle\n> ' + (item.params.src || 'telegram') + '\n\n## Notizen\n\n- \n\n## Naechste Schritte\n\n- [ ] Review und finalisieren\n';

return [{ json: { filename, content, path: 'obsidian-vault/00_INBOX/' + filename } }];

const item = items[0].json;
const title = item.title || '';
const dateMatch = title.match(/(\d{4}-\d{2}-\d{2})/);
const queryDate = dateMatch ? dateMatch[1] : new Date().toISOString().split('T')[0];
const window = item.params.window || '09:00-17:00';
const parts = window.split('-');
const tz = item.params.tz || 'Europe/Berlin';

return [{
  json: {
    timeMin: queryDate + 'T' + parts[0] + ':00',
    timeMax: queryDate + 'T' + parts[1] + ':00',
    timeZone: tz,
    queryDate,
    chat_id: item.chat_id,
    event_id: item.event_id
  }
}];
